import{_ as a,H as n,f as t,i as p}from"./chunks/framework.BHvCMIhP.js";const u=JSON.parse('{"title":"队列、缓存与消息:Redis、MQ、异步任务的入门常识","description":"","frontmatter":{},"headers":[],"relativePath":"cloudBasicsLearning/17-队列缓存与消息.md","filePath":"cloudBasicsLearning/17-队列缓存与消息.md","lastUpdated":1779015580000}'),e={name:"cloudBasicsLearning/17-队列缓存与消息.md"};function i(l,s,d,c,o,r){return n(),t("div",null,[...s[0]||(s[0]=[p(`<h1 id="队列、缓存与消息-redis、mq、异步任务的入门常识" tabindex="-1">队列、缓存与消息:Redis、MQ、异步任务的入门常识 <a class="header-anchor" href="#队列、缓存与消息-redis、mq、异步任务的入门常识" aria-label="Permalink to &quot;队列、缓存与消息:Redis、MQ、异步任务的入门常识&quot;">​</a></h1><p>小项目一开始通常是&quot;请求来了就现场处理&quot;。用户点按钮,后端查数据库,生成结果,返回页面。这个模型简单直接,但当任务变慢、并发变高、外部服务不稳定时,你就会需要缓存、队列和消息系统。</p><blockquote><p>一句话先记住:缓存是为了少做重复读取,队列是为了把慢任务放到后台排队做,消息是为了让系统之间可靠传递事件;它们都不是数据库替代品。</p></blockquote><hr><h2 id="一、一句话解释" tabindex="-1">一、一句话解释 <a class="header-anchor" href="#一、一句话解释" aria-label="Permalink to &quot;一、一句话解释&quot;">​</a></h2><p>这三个词经常一起出现,但解决的问题不同。</p><p>缓存:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>把常用结果临时放起来,下次更快读取</span></span></code></pre></div><p>典型产品是 Redis、Memcached、Cloudflare KV、Upstash Redis。常见用途:</p><ul><li>登录 Session</li><li>热门配置</li><li>API 查询结果</li><li>排行榜</li><li>限流计数器</li><li>短期验证码</li></ul><p>队列:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>把任务先放进队伍,后台 Worker 一个个处理</span></span></code></pre></div><p>典型产品是 SQS、RabbitMQ、Kafka、阿里云 MNS / RocketMQ、腾讯云 CMQ / TDMQ、Cloudflare Queues。常见用途:</p><ul><li>发邮件</li><li>图片压缩</li><li>视频转码</li><li>生成报表</li><li>Webhook 重试</li><li>批量导入</li></ul><p>消息:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一个系统发生了事件,通知其他系统</span></span></code></pre></div><p>常见事件:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>user.created</span></span>
<span class="line"><span>order.paid</span></span>
<span class="line"><span>file.uploaded</span></span>
<span class="line"><span>invoice.failed</span></span>
<span class="line"><span>comment.created</span></span></code></pre></div><p>缓存、队列、消息最容易和数据库混淆。数据库保存事实,缓存保存临时副本,队列保存待处理任务,消息保存事件通知。它们可以一起用,但职责不同。</p><hr><h2 id="二、放在系统哪里" tabindex="-1">二、放在系统哪里 <a class="header-anchor" href="#二、放在系统哪里" aria-label="Permalink to &quot;二、放在系统哪里&quot;">​</a></h2><p>缓存通常放在后端和数据库之间:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户请求</span></span>
<span class="line"><span>  -&gt; 后端 API</span></span>
<span class="line"><span>  -&gt; Redis 缓存</span></span>
<span class="line"><span>  -&gt; 数据库</span></span></code></pre></div><p>一次典型读取:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>后端查 Redis</span></span>
<span class="line"><span>  -&gt; 命中:返回缓存结果</span></span>
<span class="line"><span>  -&gt; 未命中:查数据库</span></span>
<span class="line"><span>  -&gt; 写入 Redis,设置过期时间</span></span>
<span class="line"><span>  -&gt; 返回结果</span></span></code></pre></div><p>队列通常放在请求处理和后台 Worker 之间:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户提交导出任务</span></span>
<span class="line"><span>  -&gt; 后端创建任务记录</span></span>
<span class="line"><span>  -&gt; 消息进入队列</span></span>
<span class="line"><span>  -&gt; Worker 异步生成文件</span></span>
<span class="line"><span>  -&gt; 文件上传对象存储</span></span>
<span class="line"><span>  -&gt; 数据库更新任务状态</span></span>
<span class="line"><span>  -&gt; 用户稍后下载</span></span></code></pre></div><p>消息系统通常放在多个服务之间:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>支付服务确认订单已支付</span></span>
<span class="line"><span>  -&gt; 发布 order.paid 消息</span></span>
<span class="line"><span>  -&gt; 邮件服务发送收据</span></span>
<span class="line"><span>  -&gt; 权限服务开通会员</span></span>
<span class="line"><span>  -&gt; 数据分析服务记录转化</span></span></code></pre></div><p>对小团队来说,最常见的不是上来就设计复杂事件架构,而是先解决两个痛点:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>热点数据反复查数据库 -&gt; 加缓存</span></span>
<span class="line"><span>慢任务拖住 HTTP 请求 -&gt; 加队列</span></span></code></pre></div><p>例如用户点击&quot;导出全部订单&quot;。如果你在 HTTP 请求里现场生成 CSV,请求可能跑 30 秒,中途超时,用户刷新又重新跑一次。更稳的方式是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 后端创建导出任务,状态为 pending</span></span>
<span class="line"><span>2. 把任务 ID 放进队列</span></span>
<span class="line"><span>3. 立即返回&quot;任务已创建&quot;</span></span>
<span class="line"><span>4. Worker 后台生成 CSV</span></span>
<span class="line"><span>5. 文件放对象存储</span></span>
<span class="line"><span>6. 数据库把任务状态改成 done</span></span></code></pre></div><hr><h2 id="三、常见套餐和使用限制" tabindex="-1">三、常见套餐和使用限制 <a class="header-anchor" href="#三、常见套餐和使用限制" aria-label="Permalink to &quot;三、常见套餐和使用限制&quot;">​</a></h2><p>缓存服务常见限制:</p><table tabindex="0"><thead><tr><th>限制项</th><th>说明</th><th>常见风险</th></tr></thead><tbody><tr><td>内存容量</td><td>Redis 主要吃内存</td><td>key 太多或 value 太大导致淘汰</td></tr><tr><td>最大连接数</td><td>客户端连接数量</td><td>Serverless 短连接打满连接数</td></tr><tr><td>QPS / 吞吐</td><td>每秒读写能力</td><td>热点 key 或限流计数器压力大</td></tr><tr><td>数据持久化</td><td>是否落盘、是否可恢复</td><td>把缓存当数据库会丢数据</td></tr><tr><td>淘汰策略</td><td>内存满了删哪些 key</td><td>重要临时数据被提前淘汰</td></tr><tr><td>网络位置</td><td>和后端是否同区域</td><td>跨区域访问增加延迟和费用</td></tr></tbody></table><p>Redis 特别容易被滥用。它很快,但快不等于适合保存所有东西。你要默认缓存可能丢:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Redis 重启</span></span>
<span class="line"><span>内存满了触发淘汰</span></span>
<span class="line"><span>过期时间到了</span></span>
<span class="line"><span>平台故障切换</span></span>
<span class="line"><span>开发者误删 key</span></span></code></pre></div><p>所以可以丢的放缓存,不能丢的进数据库。</p><p>队列和 MQ 常见限制:</p><table tabindex="0"><thead><tr><th>限制项</th><th>说明</th><th>常见风险</th></tr></thead><tbody><tr><td>消息数量</td><td>免费额度或套餐限制</td><td>突发任务堆积后超额</td></tr><tr><td>消息大小</td><td>单条消息不能太大</td><td>把文件内容塞进消息会失败</td></tr><tr><td>保留时间</td><td>消息最多保存多久</td><td>Worker 挂太久,消息过期丢失</td></tr><tr><td>投递次数</td><td>失败后重试多少次</td><td>毒消息反复失败拖垮队列</td></tr><tr><td>并发消费者</td><td>Worker 同时处理数量</td><td>太高会打爆数据库或第三方 API</td></tr><tr><td>顺序保证</td><td>是否保证先进先出</td><td>订单状态类任务需要特别注意</td></tr><tr><td>至少一次投递</td><td>消息可能重复到达</td><td>处理逻辑必须幂等</td></tr></tbody></table><p>队列最重要的一句话是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>消息可能重复,可能延迟,可能失败,但不应该让系统整体卡死。</span></span></code></pre></div><p>很多 MQ 默认追求&quot;至少一次投递&quot;,意思是平台尽量保证消息被处理,代价是同一条消息可能被投递多次。所以 Worker 不能假设&quot;这件事只会执行一次&quot;。比如扣款、发券、创建订单这类操作必须有幂等设计:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>同一个 message_id 已处理过</span></span>
<span class="line"><span>  -&gt; 直接跳过</span></span>
<span class="line"><span>否则</span></span>
<span class="line"><span>  -&gt; 执行业务</span></span>
<span class="line"><span>  -&gt; 记录已处理</span></span></code></pre></div><hr><h2 id="四、小团队建议" tabindex="-1">四、小团队建议 <a class="header-anchor" href="#四、小团队建议" aria-label="Permalink to &quot;四、小团队建议&quot;">​</a></h2><p>不要为了&quot;架构完整&quot;上 Redis 和 MQ。先问两个问题:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>有没有重复读导致数据库压力?</span></span>
<span class="line"><span>有没有慢任务导致用户请求超时?</span></span></code></pre></div><p>如果答案都是否,先不用。一个简单应用可以靠数据库和对象存储跑很久。</p><p>适合先加缓存的场景:</p><ul><li>首页热门内容读取频繁</li><li>用户权限或配置每次请求都要查</li><li>第三方 API 有速率限制</li><li>需要做登录 Session</li><li>需要做 IP 或用户级限流</li></ul><p>适合先加队列的场景:</p><ul><li>发邮件、短信、Webhook</li><li>图片压缩、视频转码</li><li>导入导出大文件</li><li>调用不稳定的第三方服务</li><li>需要失败重试</li><li>任务执行时间超过 HTTP 请求可接受时间</li></ul><p>最低限度的护栏:</p><ul><li>缓存 key 要有命名规范和过期时间</li><li>不要把唯一事实只存在 Redis</li><li>缓存失效后要能从数据库重建</li><li>队列消息里放 ID,不要放大文件本体</li><li>Worker 处理要幂等,能安全重试</li><li>设置死信队列或失败记录</li><li>控制 Worker 并发,避免后台任务打爆数据库</li><li>监控队列积压长度、失败次数、处理耗时</li><li>Redis 和 MQ 密码不要暴露到前端</li><li>生产和开发环境分开</li></ul><p>一个保守的小团队演进路径:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>阶段 1:</span></span>
<span class="line"><span>  后端 + 数据库 + 对象存储</span></span>
<span class="line"><span></span></span>
<span class="line"><span>阶段 2:</span></span>
<span class="line"><span>  加 Redis 做 Session、限流、热点缓存</span></span>
<span class="line"><span></span></span>
<span class="line"><span>阶段 3:</span></span>
<span class="line"><span>  加队列处理邮件、导出、图片压缩</span></span>
<span class="line"><span></span></span>
<span class="line"><span>阶段 4:</span></span>
<span class="line"><span>  多服务之后再考虑事件总线、Kafka、复杂 MQ</span></span></code></pre></div><p>什么时候该升级?</p><ul><li>Redis 内存经常接近上限</li><li>连接数被 Serverless 后端打满</li><li>队列积压持续增长</li><li>失败任务没有可追踪记录</li><li>后台任务影响数据库正常请求</li><li>需要更长消息保留时间或更强顺序保证</li><li>消息已经承载核心交易链路</li></ul><p>小团队常见的错误是&quot;缓存没命中就全站变慢,队列失败就没人知道&quot;。缓存和队列都是为了让系统更稳,但前提是你给它们设置了过期、重试、告警和降级。</p><hr><h2 id="五、一句话总结" tabindex="-1">五、一句话总结 <a class="header-anchor" href="#五、一句话总结" aria-label="Permalink to &quot;五、一句话总结&quot;">​</a></h2><p>Redis 解决重复读取和短期状态,MQ 解决异步任务和事件传递;小团队不要把它们当数据库,看套餐时重点看内存、连接数、消息大小、保留时间、重试语义、并发和失败处理能力。</p>`,65)])])}const g=a(e,[["render",i]]);export{u as __pageData,g as default};
